script:
frappe.ui.form.on('HD Ticket', {
    refresh: function(frm) {
       
        
        // Only show button if the document is saved (not new)
        if (!frm.is_new() ) {
            
            // Add the button to the top right menu
            frm.add_custom_button(__('💻 Connect to Client'), function() {
                
                // 1. Fetch the User linked to the user who opened the ticket (frm.doc.owner)
                console.log("frm.doc.owner :", frm.doc.owner)
                frappe.db.get_value('User', { 'email': frm.doc.owner }, 'remote_id')
                    .then(r => {
                        let remote_id = r.message ? r.message.remote_id : null;

                        if (!remote_id) {
                            frappe.msgprint({
                                title: __('Remote ID Missing'),
                                indicator: 'red',
                                message: __('The user who opened this ticket (' + frm.doc.owner + ') does not have a Remote ID saved.')
                            });
                            return;
                        }

                        // 2. Define the fixed password
                        let password = "Awqaf1234Awqaf@@Awqaf";
                        
                        // 3. Construct the RustDesk URI scheme
                        let connectUrl = "rustdesk://" + remote_id;

                       // 4. Copy password to clipboard and launch
                        const copyToClipboard = (text) => {
                            if (navigator.clipboard && window.isSecureContext) {
                                return navigator.clipboard.writeText(text);
                            } else {
                                let textArea = document.createElement("textarea");
                                textArea.value = text;
                                textArea.style.position = "fixed"; 
                                textArea.style.opacity = "0";
                                document.body.appendChild(textArea);
                                textArea.select();
                                return new Promise((resolve, reject) => {
                                    document.execCommand('copy') ? resolve() : reject();
                                    textArea.remove();
                                });
                            }
                        };
                        
                        copyToClipboard(password).then(function() {
                            frappe.show_alert({
                                message: __('Password copied! Opening RustDesk...'),
                                indicator: 'green'
                            }, 5); 
                            window.location.href = connectUrl;
                        }).catch(function(err) {
                            frappe.show_alert({
                                message: __('Opening RustDesk (Password copy failed)...'),
                                indicator: 'orange'
                            });
                            window.location.href = connectUrl;
                        });
                    });
            }).addClass('btn-primary'); // Make the button blue
        }
    },

    download_remote_software: function(frm) {
        // 1. Fetch Employee ID linked to the current user
        console.log("frm.doc.owner :", frappe.session.user)
        frappe.db.get_value('User', { 'email': frappe.session.user }, 'name')
            .then(r => {
                let username = r.message ? r.message.name : null;

                console.log("username :", username)
                if (!username) {
                    frappe.msgprint({
                        title: __('Error'),
                        indicator: 'red',
                        message: __('Could not find an user ID linked to your account.')
                    });
                    return;
                }

                // 2. Generate the Batch File Content
                // Note: We use double backslashes \\ inside the JS string to ensure they appear as single \ in the file
                let bat_content = `
@echo off
setlocal EnableDelayedExpansion

:: --- CONFIGURATION VARIABLES ---
set "SERVER_IP=160.19.102.66"
set "DOWNLOAD_URL=http://172.16.35.6:8090/files/rustdesk-1.4.5-x86_64.exe"

:: ERPNext API Details
set "ERP_URL=http://172.16.35.6:8090"
set "API_KEY=e206305b6060f6e"
set "API_SECRET=7e419433b101a7c"
set "TARGET_ID=${username}"

:: RustDesk Settings
set "INSTALLER_NAME=rustdesk-1.4.5-x86_64.exe"
set "PLAIN_PASSWORD=Awqaf1234Awqaf@@Awqaf"
set "KEY_STRING=X0ioaq+92YSf5qk+SObdzxEtX2qjOteCGrOdMB4JLnE="
:: --------------------------------

:: [AUTO-ELEVATION]
net session >nul 2>&1
if %errorLevel% neq 0 (
    echo Requesting Admin rights...
    echo Set UAC = CreateObject^("Shell.Application"^) > "%temp%\\getadmin.vbs"
    echo UAC.ShellExecute "%~s0", "", "", "runas", 1 >> "%temp%\\getadmin.vbs"
    "%temp%\\getadmin.vbs"
    del "%temp%\\getadmin.vbs"
    exit /b
)

echo ===================================================
echo   [Admin Confirmed] Starting Setup Process...
echo ===================================================
echo.

:: [UNINSTALL PREVIOUS VERSION]
echo ===================================================
echo   [*] PREVIOUS INSTALLATION CHECK
echo ===================================================
echo   [-] Scanning system for existing RustDesk files...
set "EXISTING_RUST="
if exist "C:\\Program Files\\RustDesk\\rustdesk.exe" set "EXISTING_RUST=C:\\Program Files\\RustDesk\\rustdesk.exe"
if exist "C:\\Program Files (x86)\\RustDesk\\rustdesk.exe" set "EXISTING_RUST=C:\\Program Files (x86)\\RustDesk\\rustdesk.exe"

if not "!EXISTING_RUST!"=="" (
    echo   [!] Old version detected.
    echo   [~] Stopping background services...
    net stop rustdesk >nul 2>&1
    
    echo   [~] Silently uninstalling previous version...
    "!EXISTING_RUST!" --silent-uninstall
    timeout /t 5 /nobreak >nul
    
    echo   [~] Wiping old configuration and keys...
    if exist "%APPDATA%\\RustDesk" rmdir /s /q "%APPDATA%\\RustDesk"
    if exist "C:\\Windows\\ServiceProfiles\\LocalService\\AppData\\Roaming\\RustDesk" rmdir /s /q "C:\\Windows\\ServiceProfiles\\LocalService\\AppData\\Roaming\\RustDesk"
    
    echo   [+] Cleanup complete! Ready for fresh installation.
) else (
    echo   [+] No previous installation found. Proceeding...
)
echo ===================================================
echo.

:: 1. Download
if not exist "%~dp0%INSTALLER_NAME%" (
    echo [1/6] Downloading Installer...
    powershell -Command "[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; Invoke-WebRequest -Uri '%DOWNLOAD_URL%' -OutFile '%~dp0%INSTALLER_NAME%'"
)

:: 2. Install
echo [2/6] Installing...
start /wait "" "%~dp0%INSTALLER_NAME%" --silent-install

:: 3. WAITING FOR FILE
echo [3/6] Waiting for installation to finish...
set "RUST_PATH="
for /L %%i in (1,1,20) do (
    if exist "C:\\Program Files\\RustDesk\\rustdesk.exe" (
        set "RUST_PATH=C:\\Program Files\\RustDesk\\rustdesk.exe"
        goto FOUND
    )
    if exist "C:\\Program Files (x86)\\RustDesk\\rustdesk.exe" (
        set "RUST_PATH=C:\\Program Files (x86)\\RustDesk\\rustdesk.exe"
        goto FOUND
    )
    timeout /t 2 /nobreak >nul
)

:FOUND
if "%RUST_PATH%"=="" (
    echo [ERROR] Installation timed out.
    pause
    exit /b
)

:: 4. Stop Service
net stop rustdesk >nul 2>&1

:: 5. Write Config
set "PATH_SERVICE=C:\\Windows\\ServiceProfiles\\LocalService\\AppData\\Roaming\\RustDesk\\config"
set "PATH_USER=%APPDATA%\\RustDesk\\config"
call :WRITE_CONFIG "%PATH_SERVICE%"
call :WRITE_CONFIG "%PATH_USER%"

:: 6. Restart & Set Password
net start rustdesk >nul 2>&1
timeout /t 5 /nobreak > NUL
"%RUST_PATH%" --password "%PLAIN_PASSWORD%"

:: 7. Send ID to ERPNext
echo [6/6] Sending ID to ERPNext...
for /f "tokens=*" %%a in ('"%RUST_PATH%" --get-id') do set "RUST_ID=%%a"

if "!RUST_ID!"=="" (
    echo [ERROR] Could not retrieve ID.
) else (
    echo ID: !RUST_ID!
    powershell -Command "try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; $res = Invoke-RestMethod -Uri '%ERP_URL%/api/resource/User/%TARGET_ID%' -Method Put -Headers @{ 'Authorization' = 'token %API_KEY%:%API_SECRET%' } -Body (@{ 'remote_id' = '!RUST_ID!' } | ConvertTo-Json) -ContentType 'application/json' -ErrorAction Stop; Write-Host 'SUCCESS' } catch { Write-Host 'FAILURE: ' $_.Exception.Message; $res }"
)

echo.
echo ===================================================
echo   [*] SETUP COMPLETE
echo ===================================================
echo   [~] Cleaning up temporary files...
timeout /t 5 >nul


:: --- CLEANUP SECTION ---
:: 1. Delete the Installer
if exist "%~dp0%INSTALLER_NAME%" del /f /q "%~dp0%INSTALLER_NAME%"

:: 2. Delete this Batch Script (Self-Destruct)
(goto) 2>nul & del "%~f0"
exit /b

:WRITE_CONFIG
set "TARGET_DIR=%~1"
set "TARGET_FILE=%TARGET_DIR%\\RustDesk2.toml"
if not exist "%TARGET_DIR%" mkdir "%TARGET_DIR%"
(
echo rendezvous_server = 'http://%SERVER_IP%'
echo nat_type = 2
echo serial = 0
echo unlock_pin = ''
echo trusted_devices = ''
echo.
echo [options]
echo custom-rendezvous-server = '%SERVER_IP%'
echo av1-test = 'Y'
echo allow-insecure-tls-fallback = 'Y'
echo verification-method = 'use-permanent-password'
echo key = '%KEY_STRING%'
) > "%TARGET_FILE%"
exit /b
`;

                // 3. Trigger Download of the .bat file only
                download_blob(bat_content, "install_remote_support.bat", "text/plain");
                
                frappe.msgprint({
                    title: __('Download Started'),
                    indicator: 'green',
                    message: __('Please run the downloaded batch file as Administrator. It will download and install the software automatically.')
                });
            });
    }
});

// Helper function to handle blob download
function download_blob(content, filename, contentType) {
    var blob = new Blob([content], { type: contentType });
    var url = URL.createObjectURL(blob);
    var link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
}
